def get_hash(data):
    return hashlib.sha256(data).hexdigest()


def check_list(fileobj):
    correct = True
    for line in fileobj:
        if line.strip() == "":
            continue
        match = re.match(r"(\w+)[ \t]+(.+)", line)
        try:
            with open(match.group(2), "rb") as f1:
                if match.group(1) == get_hash(f1.read()):
                    print(match.group(2) + ": Pass")
                else:
                    print(match.group(2) + ": Fail")
                    correct = False
        except:
            print("Invalid format.")
            correct = False
    return correct


def make_file(txt):
    f = six.BytesIO()
    f.write(txt.encode())
    f.seek(0)
    return f


def get_hash_file(fileobj):
    h = hashlib.sha256()
    chunk_size = 8192
    while True:
        chunk = fileobj.read(chunk_size)
        if len(chunk) == 0:
            break
        h.update(chunk)
    return h.hexdigest()


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("-c", "--check", help="Check a file with md5 hashes and file names for a match.")
    ap.add_argument("file", nargs="*", help="String or file to hash.")
    args = ap.parse_args()

    if args.check:
        with open(args.check, "r") as f:
            check_list(f)
    else:
        for file in args.file:
            if os.path.isfile(file):
                with open(file, "rb") as f:
                    print(get_hash_file(f))
            else:
                print(get_hash(file.encode()))


if __name__ == "__main__":
