            raise CryptoException("Invalid bundle")
    ca_bundle = b

def _JSONdefault(o):
    """Turn an object into JSON.  
    Dates and instances of classes derived from CryptoTyped get special handling"""
    if isinstance(o, datetime.datetime):
        return False
    if self.NotAfter < n:
        return False
    if len(self.Name) == 0:
        return False
    if not self.PublicKey:
        return False
    if self.json_['Version'] != version:
        return False
    ce = self.CriticalExtensions
    if ce:
        for e in ce:
            if not e.check(self):
                return False
    return True

class PublicKey(CryptoTyped):
    def __init__(self, key=None, json=None):
        super(PublicKey, self).__init__(json)
        if key:
            self.key = key
            self.Exponent = key.e
            self.Modulus = key.n
            self.Algorithm = "RSA-PKCS1-1.5"
        else:
            n = self.Modulus
            e = self.Exponent
            self.key = create_rsa(n, e)

    def verify(self, signed_data, signature, signature_algorithm="RSA-PKCS1-1.5", digest_algorithm="SHA256"):
        dig = hashlib.sha256(signed_data).digest()
        if signature_algorithm != "RSA-PKCS1-1.5":
            raise CryptoException("Unknown signature algorithm")
        try:
            self.key.verify(
                asym_padding.PSS(
                    mgf=asym_padding.MGF1(hashes.SHA256()),
                    salt_length=asym_padding.PSS.MAX_LENGTH
                ),
                signature,
                dig
            )
            return True
        except InvalidSignature:
            return False

    def encrypt(self, plaintext):
        # Generate random IV
        iv = os.urandom(16)
        # Generate random key
        key = os.urandom(32)
        # Create cipher context
        cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
        # Encrypt plaintext
        encryptor = cipher.encryptor()
        padder = padding.PKCS7(128).padder()
        padded_data = padder.update(plaintext) + padder.finalize()
        encrypted_data = encryptor.update(padded_data) + encryptor.finalize()
        # Return IV and encrypted data
        return iv + encrypted_data

class Certificate(CryptoTyped):
    def __init__(self, json=None):
        super(Certificate, self).__init__(json)
        self.PublicKey = PublicKey(json=self.json_['PublicKey'])

    def hash(self):
        pk = self.PublicKey.key        
        source = [pk.n, self.Name,
                  self.json_["NotAfter"], self.json_["NotBefore"],
                  self.Serial]
        source = [s.to_bytes(32, 'big') for s in source]
        if "CriticalExtensions" in self.json_:
            for e in self.CriticalExtensions:
                source += [e.cannon()]
        if "Extensions" in self.json_:
            for e in self.Extensions:
                source += [e.cannon()]
        source = "\x00".join(map(str, source))
        return hashlib.sha256(source.encode()).hexdigest()

    def readable_hash(self):
        dig = hashlib.sha256(self.hash().encode()).hexdigest()
        f = []
        for i in range(len(dig) / 64):
            f.append(dig[i*64:(i+1)*64])
        return ":".join(f)

