from Crypto.Cipher import AES

class aes():
	def __init__(self):
		self._key = os.urandom(32)
		self._iv = os.urandom(16)
		self._engine = AES.new(self._key, AES.MODE_CBC, self._iv)

	def encrypt(self, plaintext):
		return self._engine.encrypt(plaintext)

	def decrypt(self, plaintext):
		return self._engine.decrypt(plaintext)

	def get_key(self):
		return self._key.hex()

	def get_iv(self):
		return self._iv.hex()

	def verify(self, plaintext, signature):
		return hmac.compare_digest(self._engine.encrypt(plaintext), signature)

	def verify_key(self, key):
		return hmac.compare_digest(self._key, key)
